(function($){$(document).ready(function(){var isLoggedIn=typeof window.isLoggedIn!=='undefined'?window.isLoggedIn:false;if(isLoggedIn){return;}
function isBot(){const userAgent=navigator.userAgent.toLowerCase();const botPatterns=[/bot/,/crawl/,/slurp/,/spider/,/mediapartners/,/ia_archiver/,/google/,/bing/,/yahoo/,/baidu/,/duckduckgo/,/yandex/,/sogou/,/exabot/,/facebot/,/facebook/,/twitter/,/whatsapp/,/telegram/];return botPatterns.some(pattern=>pattern.test(userAgent));}
function loadUAParser(){return new Promise((resolve,reject)=>{if(typeof UAParser!=='undefined'){resolve();return;}
const script=document.createElement('script');script.src="https://cdnjs.cloudflare.com/ajax/libs/UAParser.js/0.7.31/ua-parser.min.js";script.async=true;script.onload=()=>resolve();script.onerror=()=>reject(new Error('Failed to load UAParser'));document.head.appendChild(script);});}
let configData={};let trackingState={isConfigLoaded:false,lastTrackingTime:0,requestQueue:[],isProcessing:false};function generateNanoId(length=21){const chars='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_';if(typeof crypto!=='undefined'&&crypto.getRandomValues){const bytes=crypto.getRandomValues(new Uint8Array(length));let id='';for(let i=0;i<length;i++){id+=chars[bytes[i]%chars.length];}
return id;}
let id='';for(let i=0;i<length;i++){id+=chars[Math.floor(Math.random()*chars.length)];}
return id;}
function getCookie(name){try{let matches=document.cookie.match(new RegExp("(?:^|; )"+name.replace(/([\.$?*|{}\(\)\[\]\\\/\+^])/g,'\\$1')+"=([^;]*)"));return matches?decodeURIComponent(matches[1]):null;}catch(e){console.warn('Cookie read error:',e);return null;}}
function setCookie(name,value,days){try{var expires="";if(days){var date=new Date();date.setTime(date.getTime()+(days*24*60*60*1000));expires="; expires="+date.toUTCString();}
document.cookie=name+"="+(value||"")+expires+"; path=/; SameSite=Lax";}catch(e){console.warn('Cookie write error:',e);}}
function getFbpFbc(){const fbp=getCookie('_fbp');const fbc=getCookie('_fbc')||(getUrlParam('fbclid')?`fb.1.${Date.now()}.${getUrlParam('fbclid')}`:null);return{fbp,fbc};}
function getUrlParam(name){try{const results=new RegExp('[?&]'+name+'=([^&#]*)').exec(window.location.href);return results?decodeURIComponent(results[1]):null;}catch(e){console.warn('URL param extraction error:',e);return null;}}
async function fetchWithTimeout(url,options={},timeoutMs=5000){const controller=new AbortController();const timeoutId=setTimeout(()=>controller.abort(),timeoutMs);try{const response=await fetch(url,{...options,signal:controller.signal});clearTimeout(timeoutId);return response;}catch(error){clearTimeout(timeoutId);if(error.name==='AbortError'){throw new Error(`Request timeout after ${timeoutMs}ms`);}
throw error;}}
async function getLocationData(){const iifTk=configData.iifTk||'21319cc31aef75';try{const response=await fetchWithTimeout(`https://ipinfo.io/json?token=${iifTk}`,{},5000);if(!response.ok)throw new Error('IPInfo request failed');const data=await response.json();return{ip_address:data.ip,city:data.city,region:data.region,country:data.country,isp:data.org};}catch(error){console.warn('IPInfo failed, using fallback:',error);try{const fallbackResponse=await fetchWithTimeout('https://api.ipify.org?format=json',{},3000);if(!fallbackResponse.ok)throw new Error('Fallback IP request failed');const fallbackData=await fallbackResponse.json();return{ip_address:fallbackData.ip,city:null,region:null,country:null,isp:null};}catch(fallbackError){console.warn('All IP services failed:',fallbackError);return{ip_address:null,city:null,region:null,country:null,isp:null};}}}
async function loadConfig(){if(trackingState.isConfigLoaded)return;const websiteUrl=window.location.hostname;try{const response=await fetchWithTimeout(`https://data.akseskonversi.com/api/get-config?url=${encodeURIComponent(websiteUrl)}`,{},10000);if(!response.ok){throw new Error(`Config request failed: ${response.status}`);}
const data=await response.json();configData={externalUrls:Array.isArray(data.urls)?data.urls:[],website:data.website,campaignId:data.campaign_id||getCampaignIdFromTag(),iifTk:'21319cc31aef75',RefIdSettings:Boolean(data.ref_id_settings)};trackingState.isConfigLoaded=true;console.log('Config loaded successfully:',configData);await initializeTracking();}catch(error){console.error("Failed to load config:",error);configData={externalUrls:[],website:websiteUrl,campaignId:getCampaignIdFromTag(),iifTk:'21319cc31aef75',RefIdSettings:false};await initializeTracking();}}
function getCampaignIdFromTag(){return $('script[data-campaign-id]').attr('data-campaign-id')||'';}
function getOrCreateVisitorId(){let visitorId=getCookie('visitorId');if(!visitorId){visitorId=generateNanoId(21);setCookie('visitorId',visitorId,3);setCookie('visitCount',1,3);}
return visitorId;}
function shouldTrackPageview(){const currentTime=new Date().getTime();const currentPage=window.location.pathname;const lastVisitTime=localStorage.getItem('lastVisitTime');const lastPage=localStorage.getItem('lastPage');const minimumTimeDifference=30000;const shouldTrack=(!lastPage||currentPage!==lastPage)||(!lastVisitTime||(currentTime-parseInt(lastVisitTime))>minimumTimeDifference);if(shouldTrack){localStorage.setItem('lastVisitTime',currentTime);localStorage.setItem('lastPage',currentPage);trackingState.lastTrackingTime=currentTime;}
return shouldTrack;}
function detectTrafficSource(){const gclid=getUrlParam('gclid');const fbclid=getUrlParam('fbclid');const ttclid=getUrlParam('ttclid');const utm_source=getUrlParam('utm_source');const utm_medium=getUrlParam('utm_medium');const utm_campaign=getUrlParam('utm_campaign');const utm_term=getUrlParam('utm_term');const utm_content=getUrlParam('utm_content');let traffic_source,parameter_id;if(gclid){traffic_source='google_ads';parameter_id=gclid;}else if(fbclid){traffic_source='facebook';parameter_id=fbclid;}else if(ttclid){traffic_source='tiktok';parameter_id=ttclid;}else if(utm_source||utm_medium||utm_campaign||utm_term||utm_content){traffic_source='utm';parameter_id=getOrCreateVisitorId();}else{traffic_source='organic';parameter_id=getOrCreateVisitorId();}
return{traffic_source,parameter_id,utm_source,utm_medium,utm_campaign,utm_term,utm_content};}
async function makeApiRequest(url,data,options={}){const maxRetries=options.maxRetries||3;const retryDelay=options.retryDelay||1000;const timeoutMs=options.timeout||10000;for(let attempt=1;attempt<=maxRetries;attempt++){try{const response=await fetchWithTimeout(url,{method:'POST',headers:{'Content-Type':'application/json',},body:JSON.stringify(data),credentials:'include'},timeoutMs);if(!response.ok){throw new Error(`API request failed: ${response.status}`);}
const result=await response.json();return{success:true,data:result};}catch(error){console.warn(`API request attempt ${attempt} failed:`,error);if(attempt===maxRetries){return{success:false,error:error.message};}
await new Promise(resolve=>setTimeout(resolve,retryDelay*attempt));}}}
async function trackPageview(){if(!shouldTrackPageview()){return;}
try{const visitorId=getOrCreateVisitorId();const trafficData=detectTrafficSource();const{fbp,fbc}=getFbpFbc();const event_id=generateNanoId(21);localStorage.setItem('event_id',event_id);const parser=new UAParser();const uaResult=parser.getResult();const trackingPayload={campaign_id:configData.campaignId,visitor_id:visitorId,website:window.location.hostname,page:window.location.pathname,timestamp:new Date().toISOString(),...trafficData,referrer:document.referrer,user_agent:navigator.userAgent,browser:{name:uaResult.browser.name,version:uaResult.browser.version},os:{name:uaResult.os.name,version:uaResult.os.version},device:{type:uaResult.device.type||'desktop',vendor:uaResult.device.vendor||null},fbp:fbp,fbc:fbc,event_id:event_id,event_name:'pageview',is_bot:isBot()};const locationData=await getLocationData();const finalPayload={...trackingPayload,...locationData};console.log("Sending pageview data:",finalPayload);const result=await makeApiRequest('https://data.akseskonversi.com/api/stats',finalPayload);if(result.success){const responseData=result.data;if(responseData.ref_id){localStorage.setItem('ref_id',responseData.ref_id);console.log("ref_id stored:",responseData.ref_id);}
if(responseData.visitor_id){setCookie('visitorId',responseData.visitor_id,3);console.log("visitor_id updated:",responseData.visitor_id);}}else{console.error("Pageview tracking failed:",result.error);}}catch(error){console.error("Pageview tracking error:",error);}}
async function trackOutboundClick(element,pattern){const originalUrl=$(element).attr('href');let trackingSuccess=false;try{const visitorId=getOrCreateVisitorId();const elementId=$(element).attr('id')||null;const elementTitle=$(element).attr('title')||$(element).text().substring(0,50);const currentPage=window.location.pathname;const event_id=generateNanoId(21);localStorage.setItem('event_id',event_id);const clickData={website:window.location.hostname,page:currentPage,visitor_id:visitorId,button_url:originalUrl.replace('{cid}',encodeURIComponent(event_id)),event_id:event_id,event_name:'outbound click',last_event_time:new Date().toISOString(),element_id:elementId,element_title:elementTitle,campaign_id:configData.campaignId};console.log("Sending outbound click data:",clickData);const result=await makeApiRequest('https://data.akseskonversi.com/api/stats/event',clickData,{timeout:5000});trackingSuccess=result.success;if(!trackingSuccess){console.warn("Click tracking failed:",result.error);}}catch(error){console.error("Click tracking error:",error);}
let finalUrl=originalUrl;try{const eventId=localStorage.getItem('event_id');if(eventId){finalUrl=finalUrl.replace('{cid}',encodeURIComponent(eventId));}
if(configData.RefIdSettings&&(pattern.includes('api.whatsapp.com')||pattern.includes('wa.me'))){const refId=localStorage.getItem('ref_id');if(refId){const url=new URL(finalUrl);const predefinedMessage=url.searchParams.get("text");if(predefinedMessage){url.searchParams.set("text",predefinedMessage+` [Ref:${refId}]`);finalUrl=url.toString();}}}}catch(e){console.warn("URL modification failed, using original:",e);finalUrl=originalUrl;}
return finalUrl;}
function attachClickHandlers(){if(!configData.externalUrls||configData.externalUrls.length===0){return;}
configData.externalUrls.forEach(function(pattern){try{$("a[href*='"+pattern+"']").off('click.tracking').on('click.tracking',async function(e){e.preventDefault();const target=$(this).attr('target');const finalUrl=await trackOutboundClick(this,pattern);if(target==='_blank'){window.open(finalUrl,'_blank');}else{window.location.href=finalUrl;}});}catch(error){console.warn(`Failed to attach handler for pattern: ${pattern}`,error);}});}
function replaceTemplateVariables(){const visitorId=getOrCreateVisitorId();const eventId=localStorage.getItem('event_id');if(!visitorId){console.warn('No visitor ID available for template replacement');return;}
document.querySelectorAll('a[href*="{tcid}"], a[href*="{event_id}"]').forEach(function(link){try{let href=link.href;if(href.includes('{tcid}')&&visitorId){href=href.replace('{tcid}',encodeURIComponent(visitorId));}
if(href.includes('{event_id}')&&eventId){href=href.replace('{event_id}',encodeURIComponent(eventId));}
link.href=href;}catch(error){console.warn('Template variable replacement failed:',error);}});}
function attachFormHandlers(){document.querySelectorAll('form').forEach(function(form){let isSubmitting=false;async function handleSubmit(e){if(isSubmitting){e.preventDefault();return;}
e.preventDefault();isSubmitting=true;try{const emailInput=form.querySelector('input[type="email"]');const nameInput=form.querySelector('input[name="name"], input[name="first_name"]');if(!emailInput||!emailInput.value){console.log('No email input found, submitting form normally');return;}
const visitorId=getOrCreateVisitorId();const webhookData={tcId:visitorId,website:window.location.hostname,page:window.location.pathname,campaign_id:configData.campaignId,email:emailInput.value,name:nameInput?nameInput.value:null};console.log('Submitting form with email:',emailInput.value);const result=await makeApiRequest('https://data.akseskonversi.com/api/webhook/lead-conversion',webhookData,{timeout:5000});if(result.success){console.log('Lead conversion tracked successfully:',result.data);}else{console.warn('Lead conversion tracking failed:',result.error);}}catch(error){console.error('Form submission tracking error:',error);}finally{if(isSubmitting){form.removeEventListener('submit',handleSubmit);const submitEvent=new Event('submit',{bubbles:true,cancelable:true});if(form.dispatchEvent(submitEvent)){form.submit();}}}}
form.addEventListener('submit',handleSubmit);});}
async function initializeTracking(){try{await trackPageview();attachClickHandlers();replaceTemplateVariables();attachFormHandlers();console.log('Tracking system initialized successfully');}catch(error){console.error('Tracking initialization error:',error);}}
async function startup(){try{await loadUAParser();await loadConfig();}catch(error){console.error('Startup failed:',error);try{configData={externalUrls:[],website:window.location.hostname,campaignId:getCampaignIdFromTag(),iifTk:'21319cc31aef75',RefIdSettings:false};await initializeTracking();}catch(fallbackError){console.error('Fallback tracking failed:',fallbackError);}}}
startup();});})(jQuery);